const resp = $input.first().json;
const batchItem = $('Split Batches').item.json;
const slug = batchItem.slug;
const org_id = batchItem.org_id;
const html = (resp && resp.data) ? String(resp.data) : '';

if (html.length < 100) {
  return [{ json: { slug, org_id, html_ok: false, sql: 'SELECT 1 AS skip' } }];
}

const nameMatch = html.match(/<h1>([^\/<\n]+?)\s*\/\s*<span class="symbol"/i);
const name = nameMatch ? nameMatch[1].trim() : null;

const descMatch = html.match(/class="[^"]*body[^"]*markitup[^"]*">([\s\S]{0,3000}?)<\/div>/i);
let description = null;
if (descMatch) {
  description = descMatch[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 2000);
}

const memberMatch = html.match(/([\d,]+)\s+members?/i);
const member_count = memberMatch ? parseInt(memberMatch[1].replace(/,/g, ''), 10) : null;

const logoMatch = html.match(/class="[^"]*thumb[^"]*"[^>]*>[\s\S]{0,500}?<img[^>]+src="([^"]+)"/i);
const logo_url = logoMatch ? logoMatch[1] : null;

const is_recruiting = /recruiting/i.test(html);

function esc(s) { return String(s).replace(/'/g, "''"); }
const sets = ['updated_at = now()', 'is_recruiting = ' + is_recruiting];
if (name) sets.push("name = '" + esc(name) + "'");
if (description !== null) sets.push("description = '" + esc(description) + "'");
if (member_count !== null) sets.push('member_count = ' + member_count);
if (logo_url) sets.push("logo_url = '" + esc(logo_url) + "'");

const sql = "UPDATE sc_orgs SET " + sets.join(', ') + " WHERE org_id = '" + org_id + "'::uuid RETURNING slug, name, member_count";
return [{ json: { slug, org_id, name, member_count, is_recruiting, sql, html_ok: true } }];
